function restoreView(){
  let v=null;try{v=sessionStorage.getItem("tv_view");}catch(e){}
  if(!v||v==="home"||v==="results"||v==="shared")return;
  if(v==="school-detail"||v==="career-detail"){
    let d=null;try{d=sessionStorage.getItem("tv_detail");}catch(e){}
    if(d){const i=d.indexOf(":"),t=d.slice(0,i),id=d.slice(i+1);
      if(t==="school"&&typeof openSchool==="function"){openSchool(id);return;}
      if(t==="career"&&typeof openCareer==="function"){openCareer(id);return;}
    }
    return;
  }
  if(document.getElementById("view-"+v))showView(v);
}
if(!checkSharedPlan()&&!checkSharedCost())restoreView();

/* ===== ANIMATED GRID BEAMS: light beams traveling along the background grid lines ===== */
function initGridFlow(){
  if(window.matchMedia&&window.matchMedia("(prefers-reduced-motion: reduce)").matches)return;
  let host=document.getElementById("grid-flow");
  if(!host){host=document.createElement("div");host.id="grid-flow";host.className="grid-flow";host.setAttribute("aria-hidden","true");document.body.appendChild(host);}
  function build(){
    const cell=parseInt(getComputedStyle(document.body).getPropertyValue("--grid-cell"))||52;
    const cols=Math.floor(window.innerWidth/cell);
    const vCount=Math.max(3,Math.min(6,Math.floor(cols/4)));
    const pick=(n,max)=>{const s=new Set();let guard=0;while(s.size<Math.min(n,max-1)&&guard++<200)s.add(1+Math.floor(Math.random()*(max-1)));return[...s];};
    host.innerHTML="";
    const frag=document.createDocumentFragment();
    pick(vCount,cols).forEach(c=>{
      const el=document.createElement("span");
      el.className="gline"+(Math.random()<0.5?" up":"");
      el.style.left=(c*cell)+"px";
      el.style.setProperty("--d",(5+Math.random()*4).toFixed(1)+"s");
      el.style.setProperty("--delay",(Math.random()*5).toFixed(1)+"s");
      frag.appendChild(el);
    });
    host.appendChild(frag);
  }
  build();
  let t;window.addEventListener("resize",()=>{clearTimeout(t);t=setTimeout(build,250);});
}

/* ===== HERO FLOATING 3D GLASS CARDS (perspective curve + parallax) ===== */
function initHero3D(){
  const host=document.getElementById("hero3d");
  if(!host||host.dataset.built)return;
  host.dataset.built="1";
  const BAR=[1,2,1,1,3,1,2,1,1,3,1,1,2,1,2,1,3,1,1,2,1,3,1,2,1,1,2,1];
  // scattered "label" cards вҖ” tap one to focus it to centre (Careerpass-themed)
  const cards=[
    {view:"quiz",   title:"бһҸбҹҒбһҹбҹ’бһҸбһўбһ¶бһҮбһёбһ–",   sub1:"бһҹбҹ’бһӮбһ¶бһӣбҹӢбһҒбҹ’бһӣбһҪбһ“бһҜбһ„",     sub2:"бһ…бҹҶбһҺбһјбһӣбһ…бһ·бһҸбҹ’бһҸ бһ“бһ·бһ„бһҮбҹҶбһ“бһ¶бһү", since:"бһҘбһҸбһӮбһ·бһҸбһҗбҹ’бһӣбҹғ",   bg:"#624EBC", fg:"#F1EEFB", idle:{x:-82,y:-70,r:-11}},
    {view:"careers",title:"бһўбһ¶бһҮбһёбһ–",         sub1:"бһўбһ¶бһҮбһёбһ– бҹЎбҹ бҹ + бһҳбһ»бһҒ",    sub2:"бһӮбҹ’бһҡбһ”бҹӢбһңбһ·бһҹбҹҗбһҷбһҖбһ¶бһҡбһ„бһ¶бһҡ",   since:"бҹЎбҹў бһңбһ·бһҹбҹҗбһҷ",   bg:"#5CAD60", fg:"#12210F", idle:{x:-48,y:66,r:9}},
    {view:"schools",title:"бһҹбһ¶бһӣбһ¶",           sub1:"бһҹбһ¶бһҖбһӣбһңбһ·бһ‘бҹ’бһҷбһ¶бһӣбҹҗбһҷ бҹӨбҹЎ",  sub2:"бһҡбһҠбҹ’бһӢ бһ“бһ·бһ„бһҜбһҖбһҮбһ“",       since:"бһ‘бһјбһ‘бһ¶бҹҶбһ„бһ”бҹ’бһҡбһ‘бҹҒбһҹ",bg:"#1C2E8A", fg:"#E8EDF8", idle:{x:12,y:-14,r:-4}},
    {view:"cost",   title:"бһҗбҹ’бһӣбҹғбһҹбһ·бһҖбҹ’бһҹбһ¶",     sub1:"бһӮбһҺбһ“бһ¶бһҗбҹ’бһӣбҹғбһҹбһ·бһҖбҹ’бһҹбһ¶",     sub2:"бһҖбһ¶бһҡбһңбһ·бһ—бһ¶бһӮ ROI",       since:"бһ§бһ”бһҖбһҡбһҺбҹҚ",     bg:"#E08030", fg:"#2A1A06", idle:{x:68,y:62,r:14}},
    {view:"facts",  title:"бһҸбһҫбһўбҹ’бһ“бһҖбһҠбһ№бһ„бһ‘бҹҒ?",   sub1:"бһҖбһ¶бһҡбһ–бһ·бһҸ бһ“бһ·бһ„бһҹбҹ’бһҗбһ·бһҸбһ·",  sub2:"бһўбҹҶбһ–бһёбһҖбһ¶бһҡбһўбһ”бҹӢбһҡбҹҶ",       since:"бһҹбҹ’бһңбҹӮбһ„бһҷбһӣбҹӢ",   bg:"#D43C3C", fg:"#FAE8E8", idle:{x:84,y:-86,r:18}}
  ];
  let selected=null;
  const els=[];
  function faceHTML(c,s){
    const P=n=>+(n*s).toFixed(2);
    const bars=BAR.map(w=>`<span style="width:${P(w*1.5)}px;background:${c.fg};opacity:.8"></span>`).join("");
    return `<div class="lc-face" style="padding:${P(12)}px ${P(14)}px ${P(11)}px">
      <div class="lc-top" style="margin-bottom:${P(9)}px">
        <div class="lc-titlewrap" style="gap:${P(6)}px">
          <span style="font-size:${P(16)}px;font-weight:900;color:${c.fg};opacity:.9;line-height:1">вңі</span>
          <span style="font-size:${P(18)}px;font-weight:800;color:${c.fg};letter-spacing:-.02em;line-height:1.05">${c.title}</span>
        </div>
        <span style="font-size:${P(9)}px;font-weight:600;color:${c.fg};opacity:.5;letter-spacing:.05em;text-transform:uppercase;white-space:nowrap">${c.since}</span>
      </div>
      <div style="height:1px;background:${c.fg};opacity:.22;margin-bottom:${P(9)}px;flex-shrink:0"></div>
      <div class="lc-body">
        <div>
          <p style="margin:0;font-size:${P(11.5)}px;font-weight:600;color:${c.fg};line-height:1.35">${c.sub1}</p>
          <p style="margin:${P(3)}px 0 0;font-size:${P(11)}px;font-weight:400;color:${c.fg};opacity:.6;line-height:1.35">${c.sub2}</p>
        </div>
        <div class="lc-bottom">
          <div class="lc-bars" style="height:${P(28)}px;gap:${P(1.2)}px">${bars}</div>
          <div class="lc-logo" style="gap:${P(3)}px">
            <div class="lc-circle" style="width:${P(28)}px;height:${P(28)}px;border:${P(1.5)}px solid ${c.fg};opacity:.85">
              <span style="font-size:${P(7.5)}px;font-weight:800;color:${c.fg};line-height:1">TV</span>
            </div>
            <span style="font-size:${P(6.5)}px;font-weight:700;color:${c.fg};letter-spacing:.1em;text-transform:uppercase;opacity:.7">VISAI</span>
          </div>
        </div>
      </div>
    </div>`;
  }
  function apply(o){
    const s=o.s;
    if(selected===o.c.view){o.el.style.setProperty("--x","0px");o.el.style.setProperty("--y","0px");o.el.style.setProperty("--r","0deg");o.el.style.setProperty("--s","1.06");o.el.style.zIndex="20";}
    else{o.el.style.setProperty("--x",(o.c.idle.x*s).toFixed(1)+"px");o.el.style.setProperty("--y",(o.c.idle.y*s).toFixed(1)+"px");o.el.style.setProperty("--r",o.c.idle.r+"deg");o.el.style.setProperty("--s","1");o.el.style.zIndex="2";}
  }
  function layout(){
    const cw=Math.min(300,Math.floor((host.clientWidth||480)/1.56));
    const s=cw/300, ch=Math.round(cw*9/16);
    els.forEach(o=>{o.s=s;o.el.style.width=cw+"px";o.el.style.height=ch+"px";o.el.innerHTML=faceHTML(o.c,s);apply(o);});
  }
  cards.forEach(c=>{
    const el=document.createElement("div");
    el.className="lc-card";el.style.background=c.bg;el.dataset.view=c.view;
    const o={el,c,s:1};
    el.addEventListener("click",()=>{selected=(selected===c.view?null:c.view);els.forEach(apply);host.classList.toggle("lc-focused",selected!==null);});
    host.appendChild(el);els.push(o);
  });
  const hint=document.createElement("div");hint.className="lc-hint";hint.textContent="бһ…бһ»бһ…бһӣбһҫбһҖбһ¶бһҸбһҠбһҫбһҳбҹ’бһ”бһёбһ•бҹ’бһҠбҹ„бһҸ";host.appendChild(hint);
  layout();
  let t;window.addEventListener("resize",()=>{clearTimeout(t);t=setTimeout(layout,200);});
}

